module top_module(
  input clk,
  input reset,
  input [7:0] data,
  output reg match
);reg [7:0] last_value;

always @(posedge clk or posedge reset) begin
  if (reset) begin
    match <= 0;
    last_value <= 0;
  end else begin
    if (data > last_value) begin
      match <= 1;
    end else begin
      match <= 0;
    end
    last_value <= data;
  end
end

endmodule
